241: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onResetStream(Http::StreamResetReason,
242:                                                                         absl::string_view) {
243:   const bool expected_reset = expect_reset_;
244:   const bool goaway = received_no_error_goaway_;
245:   resetState();
246: 
247:   if (expected_reset) {
248:     // Stream reset was initiated by us (bogus gRPC response, timeout or cluster host is going
249:     // away). In these cases health check failure has already been reported and a GOAWAY (if any)
250:     // has already been handled, so just return.
251:     return;
252:   }
253: 
254:   ENVOY_CONN_LOG(debug, "connection/stream error health_flags={}", *client_,
255:                  HostUtility::healthFlagsToString(*host_));
256: 
257:   if (goaway || !parent_.reuse_connection_) {
258:     // Stream reset was unexpected, so we haven't closed the connection
259:     // yet in response to a GOAWAY or due to disabled connection reuse.
260:     client_->close(Network::ConnectionCloseType::Abort);
261:   }
262: 
263:   // TODO(baranov1ch): according to all HTTP standards, we should check if reason is one of
264:   // Http::StreamResetReason::RemoteRefusedStreamReset (which may mean GOAWAY),
265:   // Http::StreamResetReason::RemoteReset or Http::StreamResetReason::ConnectionTermination (both
266:   // mean connection close), check if connection is not fresh (was used for at least 1 request)
267:   // and silently retry request on the fresh connection. This is also true for HTTP/1.1 healthcheck.
268:   handleFailure(envoy::data::core::v3::NETWORK);
269: }
270: 
271: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onGoAway(
272:     Http::GoAwayErrorCode error_code) {
273:   ENVOY_CONN_LOG(debug, "connection going away health_flags={}", *client_,
274:                  HostUtility::healthFlagsToString(*host_));
275:   // If we have an active health check probe and receive a GOAWAY indicating
276:   // graceful shutdown, allow the probe to complete before closing the connection.
277:   // The connection will be closed when the active check completes or another
278:   // terminal condition occurs, such as a timeout or stream reset.
279:   if (request_encoder_ && error_code == Http::GoAwayErrorCode::NoError) {
280:     received_no_error_goaway_ = true;
281:     return;
282:   }
283: 
284:   // Even if we have active health check probe, fail it on GOAWAY and schedule new one.
285:   if (request_encoder_) {
286:     handleFailure(envoy::data::core::v3::NETWORK);
287:     // request_encoder_ can already be destroyed if the host was removed during the failure callback
288:     // above.
289:     if (request_encoder_ != nullptr) {
290:       expect_reset_ = true;
291:       request_encoder_->getStream().resetStream(Http::StreamResetReason::LocalReset);
292:     }
293:   }
294:   // client_ can already be destroyed if the host was removed during the failure callback above.
295:   if (client_ != nullptr) {
296:     client_->close(Network::ConnectionCloseType::Abort);
297:   }
298: }
